@namespace sv_172c7f89ee6d47798c2b5166d09969e6.Components.Pages.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-option" @onclick="() => SelectEmoji(emoji)" title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "🚀"];

    private async Task SelectEmoji(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 6px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px 6px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.emoji-option:hover {
    background: var(--bs-tertiary-bg, #f0f0f0);
}

@namespace sv_172c7f89ee6d47798c2b5166d09969e6.Components.Pages.Chat

<div class="message-input">
    <textarea class="message-textarea" 
              @bind="_text" 
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder" 
              rows="2"></textarea>
    <button class="send-btn" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSend { get; set; }

    private string _text = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        var content = _text.Trim();
        if (string.IsNullOrEmpty(content)) return;

        _text = string.Empty;
        await OnSend.InvokeAsync(content);
    }
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid var(--bs-border-color, #dee2e6);
    background: var(--bs-body-bg, #fff);
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
}

.message-textarea:focus {
    border-color: var(--bs-primary, #0d6efd);
    box-shadow: 0 0 0 2px rgba(13, 110, 253, 0.15);
}

.send-btn {
    background: var(--bs-primary, #0d6efd);
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 20px;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    align-self: flex-end;
}

.send-btn:hover:not(:disabled) {
    background: var(--bs-primary-dark, #0b5ed7);
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@namespace sv_172c7f89ee6d47798c2b5166d09969e6.Components.Pages.Chat

@using sv_172c7f89ee6d47798c2b5166d09969e6.Services

<div class="channel-item @(IsSelected ? "selected" : "")" @onclick="OnSelected">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-description">@TruncateDescription(Channel.Description)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsSelected { get; set; }
    [Parameter, EditorRequired] public EventCallback OnSelected { get; set; }

    private static string TruncateDescription(string desc) =>
        desc.Length > 40 ? string.Concat(desc.AsSpan(0, 40), "…") : desc;
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item.selected {
    background: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    color: #e0e0e0;
}

.selected .channel-name {
    color: #fff;
}

.unread-badge {
    background: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.75rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@namespace sv_172c7f89ee6d47798c2b5166d09969e6.Components.Pages.Chat

@using sv_172c7f89ee6d47798c2b5166d09969e6.Services

<div class="message-item" @onmouseenter="() => _showActions = true" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions-row">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="OnOpenThread">
            💬 @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
            <span class="thread-time">· last @FormatRelativeTime(ThreadSummary.LastReplyAt)</span>
        </button>
    }

    @if (_showActions)
    {
        <div class="action-bar">
            <button class="action-btn" @onclick="OnOpenThread" title="Reply in thread">💬 Reply</button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀 React</button>
        </div>

        @if (_showEmojiPicker)
        {
            <div class="emoji-picker-container">
                <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter, EditorRequired] public EventCallback OnOpenThread { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker()
    {
        _showEmojiPicker = !_showEmojiPicker;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background: var(--bs-tertiary-bg, #f8f9fa);
}

.message-header {
    display: flex;
