    font-size: 0.75rem;
    color: var(--bs-secondary-color, #6c757d);
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: var(--bs-tertiary-bg, #f0f0f0);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
}

.reaction-badge:hover {
    background: var(--bs-primary-bg-subtle, #cfe2ff);
    border-color: var(--bs-primary-border-subtle, #9ec5fe);
}

.thread-link {
    background: none;
