@namespace sv_172c7f89ee6d47798c2b5166d09969e6.Components.Pages.Chat

<div class="message-input">
    <textarea class="message-textarea" 
              @bind="_text" 
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder" 
              rows="2"></textarea>
    <button class="send-btn" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(_text)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonText { get; set; } = "Send";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSend { get; set; }

    private string _text = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        var content = _text.Trim();
        if (string.IsNullOrEmpty(content)) return;

        _text = string.Empty;
        await OnSend.InvokeAsync(content);
    }
}

