.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid var(--bs-border-color, #dee2e6);
    background: var(--bs-body-bg, #fff);
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
}

.message-textarea:focus {
    border-color: var(--bs-primary, #0d6efd);
    box-shadow: 0 0 0 2px rgba(13, 110, 253, 0.15);
}

.send-btn {
    background: var(--bs-primary, #0d6efd);
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 20px;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    align-self: flex-end;
}

.send-btn:hover:not(:disabled) {
    background: var(--bs-primary-dark, #0b5ed7);
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

