toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background: var(--bs-tertiary-bg, #f8f9fa);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.message-time {
    font-size: 0.75rem;
    color: var(--bs-secondary-color, #6c757d);
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: var(--bs-tertiary-bg, #f0f0f0);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
}

.reaction-badge:hover {
    background: var(--bs-primary-bg-subtle, #cfe2ff);
    border-color: var(--bs-primary-border-subtle, #9ec5fe);
}

.thread-link {
    background: none;
    border: none;
    color: var(--bs-primary, #0d6efd);
    font-size: 0.8rem;
    font-weight: 600;
    padding: 4px 0;
    cursor: pointer;
    margin-top: 4px;
    display: inline-flex;
    align-items: center;
    gap: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.thread-time {
    font-weight: 400;
    color: var(--bs-secondary-color, #6c757d);
}

.action-bar {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.78rem;
    border-radius: 4px;
    cursor: pointer;
    white-space: nowrap;
}

.action-btn:hover {
    background: var(--bs-tertiary-bg, #f0f0f0);
}

.emoji-picker-container {
    position: absolute;
    top: -50px;
    right: 16px;
    z-index: 20;
}

