    font-size: 1.1rem;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 4px;
    color: var(--bs-secondary-color, #6c757d);
    line-height: 1;
}

.close-btn:hover {
    background: var(--bs-tertiary-bg, #f0f0f0);
    color: var(--bs-body-color, #212529);
}

.thread-root-quote {
    padding: 12px 16px;
    background: var(--bs-tertiary-bg, #f8f9fa);
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
    flex-shrink: 0;
}

.root-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.root-content {
    margin: 4px 0 0;
