.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.reply-count-divider {
    display: flex;
    align-items: center;
    padding: 8px 16px;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--bs-secondary-color, #6c757d);
}

.reply-count-divider::after {
    content: "";
    flex: 1;
    height: 1px;
    background: var(--bs-border-color, #dee2e6);
    margin-left: 8px;
}

.thread-reply {
    padding: 8px 16px;
}

.thread-reply:hover {
    background: var(--bs-tertiary-bg, #f8f9fa);
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.72rem;
    color: var(--bs-secondary-color, #6c757d);
}

.reply-content {
    font-size: 0.85rem;
    line-height: 1.4;
    word-break: break-word;
}

