@namespace sv_172c7f89ee6d47798c2b5166d09969e6.Components.Pages.Chat

@using sv_172c7f89ee6d47798c2b5166d09969e6.Services

<div class="message-area">
    <div class="area-header">
        @if (CurrentChannel is not null)
        {
            <h6 class="header-channel"># @CurrentChannel.Name</h6>
            @if (!string.IsNullOrWhiteSpace(CurrentChannel.Description))
            {
                <span class="header-description">@CurrentChannel.Description</span>
            }
        }
    </div>

    <div class="message-list">
        @if (HasMoreMessages)
        {
            <div class="load-more">
                <button class="load-more-btn" @onclick="OnLoadMore" disabled="@IsLoadingMore">
                    @(IsLoadingMore ? "Loading…" : "⬆ Load older messages")
                </button>
            </div>
        }

        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ThreadSummary="GetThreadSummary(msg.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                         OnReact="emoji => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{CurrentChannel?.Name ?? "channel"}…")"
                  ButtonText="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter, EditorRequired] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter, EditorRequired] public EventCallback OnLoadMore { get; set; }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.GetValueOrDefault(messageId);
}

