.thread-panel {
    display: flex;
    flex-direction: column;
    width: 340px;
    min-width: 280px;
    border-left: 1px solid var(--bs-border-color, #dee2e6);
    background: var(--bs-body-bg, #fff);
    flex-shrink: 0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
    flex-shrink: 0;
}

.thread-title {
    margin: 0;
    font-weight: 700;
    font-size: 1rem;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 4px;
    color: var(--bs-secondary-color, #6c757d);
    line-height: 1;
}

.close-btn:hover {
    background: var(--bs-tertiary-bg, #f0f0f0);
    color: var(--bs-body-color, #212529);
}

.thread-root-quote {
    padding: 12px 16px;
    background: var(--bs-tertiary-bg, #f8f9fa);
    border-bottom: 1px solid var(--bs-border-color, #dee2e6);
    flex-shrink: 0;
}

.root-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.root-content {
    margin: 4px 0 0;
    font-size: 0.85rem;
    line-height: 1.4;
    color: var(--bs-body-color, #212529);
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.reply-count-divider {
    display: flex;
    align-items: center;
    padding: 8px 16px;
    font-size: 0.75rem;
    font-weight: 600;
    color: var(--bs-secondary-color, #6c757d);
}

.reply-count-divider::after {
    content: "";
    flex: 1;
    height: 1px;
    background: var(--bs-border-color, #dee2e6);
    margin-left: 8px;
}

.thread-reply {
    padding: 8px 16px;
}

.thread-reply:hover {
    background: var(--bs-tertiary-bg, #f8f9fa);
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.72rem;
    color: var(--bs-secondary-color, #6c757d);
}

.reply-content {
    font-size: 0.85rem;
    line-height: 1.4;
    word-break: break-word;
}

