arguments.file_text:
@page "/chat"
@rendermode InteractiveServer

@namespace sv_172c7f89ee6d47798c2b5166d09969e6.Components.Pages.Chat

@using sv_172c7f89ee6d47798c2b5166d09969e6.Services

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <ChannelList Channels="_channels"
                 SelectedChannelId="_selectedChannelId"
                 OnChannelSelected="SelectChannel" />

    <MessageArea Messages="_messages"
                 CurrentChannel="_currentChannel"
                 ThreadSummaries="_threadSummaries"
                 HasMoreMessages="_hasMoreMessages"
                 IsLoadingMore="_isLoadingMore"
                 OnOpenThread="OpenThread"
                 OnReact="HandleReaction"
                 OnSendMessage="SendMessage"
                 OnLoadMore="LoadMoreMessages" />

    @if (_isThreadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    [Inject] private IChatService ChatService { get; set; } = default!;

    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadMessages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = [];

    private int _selectedChannelId;
    private Channel? _currentChannel;
    private Message? _threadRootMessage;
    private bool _isThreadOpen;
    private bool _hasMoreMessages = true;
    private bool _isLoadingMore;

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _currentChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
        _hasMoreMessages = true;

        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _hasMoreMessages = _messages.Count >= PageSize;

        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channelId);

        // Refresh channel list to update unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(_selectedChannelId, _messages.Count, PageSize);
        _isLoadingMore = false;

        if (older.Count < PageSize)
        {
            _hasMoreMessages = false;
        }

        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(_selectedChannelId, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadMessages = await ChatService.GetThreadAsync(messageId);
        _isThreadOpen = true;
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);
        BuildThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        _messages = await ChatService.GetMessagesAsync(
            _selectedChannelId, 0, _messages.Count);
        BuildThreadSummaries();
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Where(g => _messages.Any(m => m.Id == g.Key))
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(
                    g.Key,
                    g.Count(),
                    g.Max(m => m.SentAt)));
    }
}

.chat-container {
    display: flex;
    height: calc(100vh - 7rem);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 8px;
    overflow: hidden;
    background: var(--bs-body-bg, #fff);
}

