    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        _messages = await ChatService.GetMessagesAsync(
            _selectedChannelId, 0, _messages.Count);
        BuildThreadSummaries();
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Where(g => _messages.Any(m => m.Id == g.Key))
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(
                    g.Key,
                    g.Count(),
                    g.Max(m => m.SentAt)));
    }
}

